import{_ as e,o as s,c as i,a2 as t}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Approvals And Evidence","description":"","frontmatter":{},"headers":[],"relativePath":"manual/approvals-evidence.md","filePath":"manual/approvals-evidence.md","lastUpdated":null}'),n={name:"manual/approvals-evidence.md"};function l(o,a,p,r,h,d){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="approvals-and-evidence" tabindex="-1">Approvals And Evidence <a class="header-anchor" href="#approvals-and-evidence" aria-label="Permalink to &quot;Approvals And Evidence&quot;">​</a></h1><p>Autofac uses approval gates to keep humans in the loop where the process or policy requires it. Evidence packs make the completed run reviewable after the fact.</p><h2 id="approval-gates" tabindex="-1">Approval gates <a class="header-anchor" href="#approval-gates" aria-label="Permalink to &quot;Approval gates&quot;">​</a></h2><p>A workflow author adds an approval gate by placing a BPMN user task with an <code>autofac:approvalTask</code> extension. When the run reaches that task, Autofac creates an approval request and pauses the run.</p><p>Approvers should review:</p><ul><li>The requested action.</li><li>The requester and agent name.</li><li>The policy rationale.</li><li>Risk score and risk factors.</li><li>Affected systems.</li><li>Related step output and artifacts.</li></ul><h2 id="decide-an-approval" tabindex="-1">Decide an approval <a class="header-anchor" href="#decide-an-approval" aria-label="Permalink to &quot;Decide an approval&quot;">​</a></h2><p>From the UI, open the approval request and choose the appropriate decision.</p><p>From the API:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$API</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/api/approvals/&lt;approval-id&gt;/decision&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;decision&quot;:&quot;approve&quot;,&quot;comment&quot;:&quot;Reviewed generated output and risk rationale.&quot;}&#39;</span></span></code></pre></div><p>Use a comment that explains the human judgment. The decision comment becomes part of the audit trail.</p><h2 id="approval-outcomes" tabindex="-1">Approval outcomes <a class="header-anchor" href="#approval-outcomes" aria-label="Permalink to &quot;Approval outcomes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Decision</th><th>Result</th></tr></thead><tbody><tr><td>Approve</td><td>The run resumes and continues past the approval task.</td></tr><tr><td>Reject</td><td>The run stops or follows the workflow&#39;s rejection path, depending on the modeled process.</td></tr><tr><td>Request changes</td><td>The workflow can route back to an agent or authoring step if modeled.</td></tr></tbody></table><h2 id="blocking-human-questions" tabindex="-1">Blocking human questions <a class="header-anchor" href="#blocking-human-questions" aria-label="Permalink to &quot;Blocking human questions&quot;">​</a></h2><p>Agents can also ask a human a blocking question with <code>human.ask</code>. This is different from a formal approval task. The run pauses with status <code>waiting_user</code>, the question appears in the run conversation, and the agent step resumes after the answer is recorded.</p><p>Use <code>human.ask</code> for missing information. Use approval tasks for governed decisions.</p><h2 id="evidence-pack-contents" tabindex="-1">Evidence pack contents <a class="header-anchor" href="#evidence-pack-contents" aria-label="Permalink to &quot;Evidence pack contents&quot;">​</a></h2><p>An evidence pack is a schema-versioned JSON record of the run. It can include:</p><ul><li>Workflow identity and BPMN hash.</li><li>Step history.</li><li>Redacted prompts and model usage.</li><li>Tool invocations and policy decisions.</li><li>Sandbox executions.</li><li>Approval requests and decisions.</li><li>Artifacts and artifact references.</li><li>Audit log entries.</li></ul><h2 id="download-evidence" tabindex="-1">Download evidence <a class="header-anchor" href="#download-evidence" aria-label="Permalink to &quot;Download evidence&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$API</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/api/runs/&lt;run-id&gt;/evidence-pack&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span></span></code></pre></div><p>For file download flows:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$API</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/api/runs/&lt;run-id&gt;/evidence-pack/download&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> evidence-pack.json</span></span></code></pre></div><h2 id="evidence-handling" tabindex="-1">Evidence handling <a class="header-anchor" href="#evidence-handling" aria-label="Permalink to &quot;Evidence handling&quot;">​</a></h2><ul><li>Treat evidence packs as audit records. Store them where your organization keeps delivery and compliance records.</li><li>Do not place secrets in prompts, run context, or artifacts. Autofac redacts known secret paths, but operators are still responsible for safe input handling.</li><li>Preserve evidence before deleting test stacks or local volumes.</li><li>When investigating an incident, correlate evidence timestamps with API logs, connector logs, and CI/CD logs.</li></ul>`,25)])])}const u=e(n,[["render",l]]);export{k as __pageData,u as default};
